import React, { useState, useEffect } from "react";
import { BrowserRouter as Router, Routes, Route } from "react-router-dom";
import "./App.css";
import Navbar from "./components/layout/Navbar";
import HomePage from "./pages/HomePage";
import UserPortal from "./pages/UserPortal";
import IssuerPortal from "./pages/IssuerPortal";
import ServicePortal from "./pages/ServicePortal";

function App() {
  const [theme, setTheme] = useState("dark");

  useEffect(() => {
    const stored = window.localStorage.getItem("kyc-theme");
    if (stored === "light" || stored === "dark") {
      setTheme(stored);
    }
  }, []);

  const toggleTheme = () => {
    setTheme(prev => {
      const next = prev === "dark" ? "light" : "dark";
      window.localStorage.setItem("kyc-theme", next);
      return next;
    });
  };

  return (
    <div className={`app-root ${theme}`}>
      <div className="app-shell">
        <div className="app-inner">
          <Router>
            <Navbar theme={theme} onToggleTheme={toggleTheme} />
            <Routes>
              <Route path="/" element={<HomePage />} />
              <Route path="/user" element={<UserPortal />} />
              <Route path="/issuer" element={<IssuerPortal />} />
              <Route path="/service" element={<ServicePortal />} />
            </Routes>
          </Router>
        </div>
      </div>
    </div>
  );
}

export default App;
